import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function buildSocialGraph(walletAddress, chainName) {
  const txns = await client.TransactionService.getTransactionsForAddressV3(
    chainName, walletAddress, { pageSize: 100 }
  );
  const counterparties = [...new Set(
    (txns.data?.items ?? []).map(tx =>
      tx.from_address === walletAddress ? tx.to_address : tx.from_address
    ).filter(Boolean)
  )];
  return { walletAddress, counterparties, edgeCount: counterparties.length };
}
